import { useMemo, useState } from 'react';
import { Link, useNavigate, useParams } from 'react-router-dom';
import { useQuery } from '@tanstack/react-query';
import { toast } from 'sonner';
import { beaconApi } from '@/api/client';
import type { MigrationExecutionDto } from '@/api/generated/beacon-api';
import { Icon } from '@/components/Icon';
import { PageHeader } from '@/components/layout/PageHeader';
import { Tabs, type TabDef } from '@/components/Tabs';
import { DataTable, type Column } from '@/components/data/DataTable';
import { EmptyState } from '@/components/data/EmptyState';
import { ConfirmDialog } from '@/components/ui/ConfirmDialog';
import { ApiError } from '@/lib/api';
import { formatDateTime, formatNumber, formatRelativeTime } from '@/lib/format';
import {
  useMigrationJobsQuery,
  useDeleteMigrationJob,
} from './queries';
import { MIGRATION_MODE_LABEL } from '@/routes/migration-history/queries';

type TabKey = 'overview' | 'executions';

const EXECUTION_STATUS_LABEL: Record<number, string> = {
  0: 'Queued',
  1: 'Running',
  2: 'Succeeded',
  3: 'Failed',
  4: 'Cancelled',
};

function useJobExecutionsQuery(jobId: number | null) {
  return useQuery({
    queryKey: ['migration-executions', jobId] as const,
    queryFn: () => beaconApi().getMigrationExecutions(jobId!, undefined, undefined, undefined, 0, 50),
    enabled: jobId != null && Number.isFinite(jobId),
  });
}

export default function MigrationJobDetailPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const numericId = id ? Number.parseInt(id, 10) : Number.NaN;

  const listQuery = useMigrationJobsQuery();
  const executions = useJobExecutionsQuery(Number.isFinite(numericId) ? numericId : null);
  const deleteMutation = useDeleteMigrationJob();
  const [confirmDelete, setConfirmDelete] = useState(false);
  const [tab, setTab] = useState<TabKey>('overview');

  const job = useMemo(
    () => listQuery.data?.jobs.find(j => j.id === numericId) ?? null,
    [listQuery.data, numericId],
  );

  if (Number.isNaN(numericId)) {
    return (
      <div className="page">
        <PageHeader title="Migration job" />
        <EmptyState icon={<Icon.Alert size={20} />} title="Invalid job id" description={String(id)} />
      </div>
    );
  }

  if (listQuery.isLoading) {
    return (
      <div className="page">
        <PageHeader title="Migration job" sub={<span className="muted">Loading…</span>} />
      </div>
    );
  }

  if (!job) {
    return (
      <div className="page">
        <PageHeader
          title={`Migration job #${numericId}`}
          sub={<Link to="/migration-jobs" className="muted">← back to migration jobs</Link>}
        />
        <EmptyState icon={<Icon.ArrowsLR size={20} />} title="Migration job not found" />
      </div>
    );
  }

  const handleDelete = async () => {
    try {
      const result = await deleteMutation.mutateAsync({ id: job.id }) as { success: boolean; errorMessage: string | null };
      if (!result.success) {
        toast.error(result.errorMessage ?? 'Failed to delete migration job');
        return;
      }
      toast.success('Migration job deleted');
      navigate('/migration-jobs');
    } catch (err) {
      const message = err instanceof ApiError ? err.body || err.message : err instanceof Error ? err.message : 'Unknown error';
      toast.error(message);
    }
  };

  const execs = executions.data?.executions ?? [];
  const lastExec = execs[0];
  const successCount = execs.filter(e => e.status === 2).length;
  const failedCount = execs.filter(e => e.status === 3).length;

  const tabs: TabDef<TabKey>[] = [
    { key: 'overview', label: <><Icon.Layers size={13} /> Overview</> },
    { key: 'executions', label: <><Icon.Refresh size={13} /> Executions</>, count: execs.length },
  ];

  return (
    <div className="page">
      <PageHeader
        title={job.name}
        sub={
          <span className="muted">
            <Link to="/migration-jobs" className="muted">Migration jobs</Link>
            <span style={{ margin: '0 6px' }}>/</span>
            #{job.id}
          </span>
        }
        actions={
          <>
            <button
              type="button"
              className="btn"
              onClick={() => { listQuery.refetch(); executions.refetch(); }}
            >
              <Icon.Refresh size={14} className="btn__icon" />
              Refresh
            </button>
            <button
              type="button"
              className="btn btn--danger"
              onClick={() => setConfirmDelete(true)}
            >
              <Icon.X size={14} className="btn__icon" />
              Delete
            </button>
          </>
        }
      />

      <div className="kpi-grid" style={{ marginBottom: 16 }}>
        <Kpi
          dot={job.isEnabled ? 'ok' : 'warn'}
          label="Status"
          value={job.isEnabled ? 'Enabled' : 'Paused'}
          sub={MIGRATION_MODE_LABEL[job.mode as 1 | 2 | 3] ?? `mode ${job.mode}`}
        />
        <Kpi
          dot="brand"
          label="Last run"
          value={lastExec ? formatRelativeTime(lastExec.startedAt as unknown as string) : '—'}
          sub={lastExec ? EXECUTION_STATUS_LABEL[lastExec.status] ?? '—' : 'never'}
        />
        <Kpi dot="ok" label="Successes" value={formatNumber(successCount)} sub={`of last ${execs.length}`} />
        <Kpi dot={failedCount > 0 ? 'warn' : 'info'} label="Failures" value={formatNumber(failedCount)} sub={`of last ${execs.length}`} />
      </div>

      <div className="card">
        <Tabs tabs={tabs} active={tab} onChange={setTab} />

        {tab === 'overview' && <OverviewTab job={job} />}
        {tab === 'executions' && (
          <ExecutionsTab
            executions={execs}
            isLoading={executions.isLoading}
            isError={executions.isError}
            error={executions.error}
          />
        )}
      </div>

      <ConfirmDialog
        open={confirmDelete}
        title="Delete migration job"
        message={<>Delete <strong>{job.name}</strong>? Execution history will be retained.</>}
        confirmLabel="Delete"
        destructive
        busy={deleteMutation.isPending}
        onConfirm={handleDelete}
        onCancel={() => setConfirmDelete(false)}
      />
    </div>
  );
}

function Kpi({ dot, label, value, sub }: { dot: string; label: string; value: string; sub: string }) {
  return (
    <div className="kpi">
      <div className="kpi__head">
        <span className={`kpi__dot kpi__dot--${dot}`}></span>
        <span className="kpi__label">{label}</span>
      </div>
      <div className="kpi__value">{value}</div>
      <div className="kpi__sub"><span className="muted">{sub}</span></div>
    </div>
  );
}

interface OverviewJob {
  id: number;
  name: string;
  description: string;
  dataSourceName: string;
  destinationDataSourceName: string;
  destinationTable: string;
  mode: number;
  isEnabled: boolean;
  schedule: string | null;
  createdTime: string;
}

function OverviewTab({ job }: { job: OverviewJob }) {
  return (
    <div className="card__body">
      {job.description && (
        <div className="muted" style={{ fontSize: 13, marginBottom: 16 }}>
          {job.description}
        </div>
      )}
      <dl style={{ display: 'grid', gridTemplateColumns: '200px 1fr', rowGap: 8, columnGap: 12, margin: 0 }}>
        <dt className="muted">Source</dt>
        <dd><span style={{ fontWeight: 600 }}>{job.dataSourceName}</span></dd>
        <dt className="muted">Destination</dt>
        <dd>
          <span style={{ fontWeight: 600 }}>{job.destinationDataSourceName}</span>
          <span className="muted"> · </span>
          <span className="mono">{job.destinationTable}</span>
        </dd>
        <dt className="muted">Mode</dt>
        <dd><span className="pill">{MIGRATION_MODE_LABEL[job.mode as 1 | 2 | 3] ?? job.mode}</span></dd>
        <dt className="muted">Schedule</dt>
        <dd>
          {job.schedule
            ? <span className="mono">{job.schedule}</span>
            : <span className="muted">manual only</span>}
        </dd>
        <dt className="muted">Enabled</dt>
        <dd>{job.isEnabled
          ? <span className="pill pill--ok">On</span>
          : <span className="muted">Off</span>}</dd>
        <dt className="muted">Created</dt>
        <dd className="mono">{formatDateTime(job.createdTime)}</dd>
      </dl>
    </div>
  );
}

const EXEC_GRID = '0.6fr 1fr 0.8fr 1fr 1fr 0.7fr 0.8fr';

function ExecutionsTab({ executions, isLoading, isError, error }: {
  executions: MigrationExecutionDto[];
  isLoading: boolean;
  isError: boolean;
  error: unknown;
}) {
  const columns: Column<MigrationExecutionDto>[] = [
    { key: 'id', header: 'Id', render: r => <span className="muted mono">#{r.id}</span> },
    {
      key: 'started',
      header: 'Started',
      render: r => (
        <span title={formatDateTime(r.startedAt as unknown as string)}>
          {formatRelativeTime(r.startedAt as unknown as string)}
        </span>
      ),
    },
    {
      key: 'status',
      header: 'Status',
      render: r => {
        const label = EXECUTION_STATUS_LABEL[r.status] ?? `status ${r.status}`;
        if (r.status === 2) return <span className="pill pill--ok">{label}</span>;
        if (r.status === 3) return <span className="pill" style={{ color: 'var(--danger, #b3261e)' }}>{label}</span>;
        return <span className="pill">{label}</span>;
      },
    },
    {
      key: 'duration',
      header: 'Duration',
      render: r => <span className="mono">{r.executionDuration}</span>,
    },
    {
      key: 'rows',
      header: 'Rows',
      render: r => (
        <span className="muted" style={{ fontSize: 12 }}>
          {formatNumber(r.sourceRowsRead)} read · {formatNumber(r.destinationRowsWritten)} written
          {r.rowsFailed > 0 && <> · {formatNumber(r.rowsFailed)} failed</>}
        </span>
      ),
    },
    {
      key: 'retry',
      header: 'Retry',
      render: r => r.isRetry ? <span className="muted">#{r.retryAttempt}</span> : <span className="muted">—</span>,
    },
    {
      key: 'error',
      header: 'Error',
      render: r => r.errorMessage
        ? <span className="muted" title={r.errorMessage} style={{ fontSize: 12 }}>
            {r.errorMessage.length > 50 ? `${r.errorMessage.slice(0, 50)}…` : r.errorMessage}
          </span>
        : <span className="muted">—</span>,
    },
  ];

  if (isLoading) {
    return <div className="card__body"><span className="muted">Loading executions…</span></div>;
  }

  if (isError) {
    return (
      <div className="card__body">
        <EmptyState
          icon={<Icon.Alert size={20} />}
          title="Failed to load executions"
          description={error instanceof Error ? error.message : 'Unknown error'}
        />
      </div>
    );
  }

  return (
    <div className="card__body card__body--flush">
      <DataTable
        columns={columns}
        rows={executions}
        rowKey={r => r.id}
        gridTemplate={EXEC_GRID}
        empty={
          <EmptyState
            icon={<Icon.Refresh size={20} />}
            title="No executions yet"
            description="Runs will appear here after the first execution."
          />
        }
      />
    </div>
  );
}
